class Solution {
public:
    int minLength(string s) {
        int count = 0;
        while (true) {
            size_t ab_pos = s.find("AB");
            if (ab_pos != string::npos) {
                s.erase(ab_pos, 2);
                count++;
                continue;
            }
            size_t cd_pos = s.find("CD");
            if (cd_pos != string::npos) {
                s.erase(cd_pos, 2);
                count++;
                continue;
            }
            break;
        }
        return s.length();
    }
};

